(function(){"use strict";$('form[name="contactform"]').on("submit",function(s){s.preventDefault();var a=$(this),t=a.find('button[type="submit"]'),e=t.html(),r=a.data("api-url");t.prop("disabled",!0).html('<i class="fas fa-spinner fa-spin"></i> Sending...');var i={};a.serializeArray().forEach(function(n){i[n.name]=n.value}),new ElanRegistryAPI().post(r,i).then(function(n){window.usSuccess(n.message),a[0].reset()}).catch(function(n){console.error("Contact form submission failed:",n),window.usError(n.message||"Failed to send.")}).finally(function(){t.prop("disabled",!1).html(e)})})})();
